  1→import { getBeamRenderData } from '@/geometry/beamGeometry';
  2→import { columnOutline } from '@/geometry/columnGeometry';
  3→import { getStairRenderData } from '@/geometry/stairGeometry';
  4→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
  5→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  6→import { buildSlabElevationBands, getSlabBottomLevel, getSlabTopLevel } from './slab';
  7→import { getElevationView, projectPlanPoints } from './projection';
  8→
  9→function createSceneRect(id, category, projection, bottom, top, options = {}) {
 10→  if (!projection) return null;
 11→  if (Math.abs(projection.right - projection.left) < 1e-6) return null;
 12→  if (Math.abs(top - bottom) < 1e-6) return null;
 13→
 14→  return {
 15→    id,
 16→    category,
 17→    left: projection.left,
 18→    right: projection.right,
 19→    bottom,
 20→    top,
 21→    depth: projection.depth,
 22→    style: options.style || category,
 23→    sourceId: options.sourceId || null,
 24→  };
 25→}
 26→
 27→function buildWallRects(floor, view) {
 28→  return (floor.walls || [])
 29→    .map((wall) => {
 30→      const renderData = getWallRenderData(wall, floor.columns || []);
 31→      return createSceneRect(
 32→        `wall-elev-${wall.id}`,
 33→        'wall',
 34→        projectPlanPoints(view, renderData.outline),
 35→        floor.level ?? 0,
 36→        (floor.level ?? 0) + (wall.height ?? 0),
 37→        { sourceId: wall.id }
 38→      );
 39→    })
 40→    .filter(Boolean);
 41→}
 42→
 43→function buildSlabRects(floor, view) {
 44→  if (!floor.slab) return [];
 45→
 46→  const slabTop = getSlabTopLevel(floor.slab);
 47→  const slabBottom = getSlabBottomLevel(floor.slab);
 48→
 49→  return buildSlabElevationBands(floor.slab, view)
 50→    .map((band) => createSceneRect(
 51→      `slab-elev-${floor.slab.id}-${band.edgeIndex}`,
 52→      'slab',
 53→      band,
 54→      slabBottom,
 55→      slabTop,
 56→      { sourceId: floor.slab.id }
 57→    ))
 58→    .filter(Boolean);
 59→}
 60→
 61→function buildColumnRects(floor, view) {
 62→  return (floor.columns || [])
 63→    .map((column) => createSceneRect(
 64→      `column-elev-${column.id}`,
 65→      'column',
 66→      projectPlanPoints(view, columnOutline(column)),
 67→      floor.level ?? 0,
 68→      (floor.level ?? 0) + column.height,
 69→      { sourceId: column.id }
 70→    ))
 71→    .filter(Boolean);
 72→}
 73→
 74→function buildBeamRects(floor, view) {
 75→  return (floor.beams || [])
 76→    .map((beam) => {
 77→      const renderData = getBeamRenderData(beam, floor.columns || []);
 78→      if (!renderData) return null;
 79→      return createSceneRect(
 80→        `beam-elev-${beam.id}`,
 81→        'beam',
 82→        projectPlanPoints(view, renderData.outline),
 83→        beam.floorLevel - beam.depth,
 84→        beam.floorLevel,
 85→        { sourceId: beam.id }
 86→      );
 87→    })
 88→    .filter(Boolean);
 89→}
 90→
 91→function buildStairRects(floor, view) {
 92→  return (floor.stairs || [])
 93→    .map((stair) => {
 94→      const renderData = getStairRenderData(stair);
 95→      if (!renderData?.outline?.length) return null;
 96→      return createSceneRect(
 97→        `stair-elev-${stair.id}`,
 98→        'stair',
 99→        projectPlanPoints(view, renderData.outline),
100→        floor.level ?? 0,
101→        (floor.level ?? 0) + renderData.totalRise,
102→        { sourceId: stair.id }
103→      );
104→    })
105→    .filter(Boolean);
106→}
107→
108→function buildDoorRects(floor, view) {
109→  return (floor.doors || [])
110→    .map((door) => {
111→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
112→      if (!wall) return null;
113→      const info = doorOutlineOnWall(wall, door);
114→      return createSceneRect(
115→        `door-elev-${door.id}`,
116→        'door',
117→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
118→        (floor.level ?? 0) + (door.sillHeight ?? 0),
119→        (floor.level ?? 0) + (door.sillHeight ?? 0) + (door.height ?? 0),
120→        { sourceId: door.id }
121→      );
122→    })
123→    .filter(Boolean);
124→}
125→
126→function buildWindowRects(floor, view) {
127→  return (floor.windows || [])
128→    .map((windowItem) => {
129→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
130→      if (!wall) return null;
131→      const info = windowOutlineOnWall(wall, windowItem);
132→      return createSceneRect(
133→        `window-elev-${windowItem.id}`,
134→        'window',
135→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
136→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0),
137→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
138→        { sourceId: windowItem.id }
139→      );
140→    })
141→    .filter(Boolean);
142→}
143→
144→function computeSceneBounds(elements = [], baseLevel = 0) {
145→  if (!elements.length) {
146→    return {
147→      minX: -1000,
148→      maxX: 1000,
149→      minZ: baseLevel,
150→      maxZ: baseLevel + 3000,
151→    };
152→  }
153→
154→  return {
155→    minX: Math.min(...elements.map((element) => element.left)),
156→    maxX: Math.max(...elements.map((element) => element.right)),
157→    minZ: Math.min(baseLevel, ...elements.map((element) => element.bottom)),
158→    maxZ: Math.max(...elements.map((element) => element.top)),
159→  };
160→}
161→
162→export function buildElevationScene(floor, viewMode) {
163→  if (!floor) return null;
164→
165→  const view = getElevationView(viewMode);
166→  const elements = [
167→    ...buildWallRects(floor, view),
168→    ...buildSlabRects(floor, view),
169→    ...buildColumnRects(floor, view),
170→    ...buildBeamRects(floor, view),
171→    ...buildStairRects(floor, view),
172→    ...buildDoorRects(floor, view),
173→    ...buildWindowRects(floor, view),
174→  ].sort((a, b) => a.depth - b.depth);
175→
176→  return {
177→    viewKey: view.key,
178→    title: view.label,
179→    elements,
180→    bounds: computeSceneBounds(elements, floor.level ?? 0),
181→    groundLevel: floor.level ?? 0,
182→  };
183→}
