 4→const EPSILON = 1e-6;
 5→
 6→function getBoundaryEdges(points = []) {
 7→  if (points.length < 2) return [];
 8→
 9→  return points.map((point, index) => ({
10→    start: point,
11→    end: points[(index + 1) % points.length],
12→    index,
13→  }));
14→}
