16→function projectEdge(view, edge) {
17→  const startHorizontal = projectElevationHorizontal(view, edge.start);
18→  const endHorizontal = projectElevationHorizontal(view, edge.end);
19→  const left = Math.min(startHorizontal, endHorizontal);
20→  const right = Math.max(startHorizontal, endHorizontal);
21→
22→  if (Math.abs(right - left) < EPSILON) return null;
23→
24→  return {
25→    left,
26→    right,
27→    depth: (
28→      projectElevationDepth(view, edge.start) +
29→      projectElevationDepth(view, edge.end)
30→    ) / 2,
31→    edgeIndex: edge.index,
32→  };
33→}
