 70→export function buildSheetScene(project, sheet) {
 71→  if (!sheet) return null;
 72→
 73→  const paper = getPaperPreset(sheet.paperSize);
 74→  const titleBlock = buildTitleBlock(project, sheet, paper);
 75→  const contentArea = {
 76→    x: SHEET_MARGIN,
 77→    y: SHEET_MARGIN,
 78→    width: paper.width - SHEET_MARGIN * 2,
 79→    height: paper.height - SHEET_MARGIN * 2,
 80→  };
 81→
 82→  const viewports = (sheet.viewports || []).map((viewport) => (
 83→    buildViewportFrame(viewport, resolveSheetViewportSource(project, viewport))
 84→  ));
 85→
 86→  return {
 87→    paper,
 88→    title: getSheetDisplayLabel(sheet),
 89→    border: {
 90→      x: SHEET_MARGIN,
 91→      y: SHEET_MARGIN,
 92→      width: paper.width - SHEET_MARGIN * 2,
 93→      height: paper.height - SHEET_MARGIN * 2,
 94→    },
 95→    contentArea,
 96→    titleBlock,
 97→    viewports,
 98→  };
 99→}
