117→export function getDefaultViewportRect(sheet, source, scale = 100) {
118→  const paper = getPaperPreset(sheet.paperSize);
119→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
120→  const denom = Math.max(1, scale);
121→  const width = Math.max(70, Math.min((bounds.maxX - bounds.minX) / denom + CONTENT_PADDING * 2, paper.width - SHEET_MARGIN * 2));
122→  const height = Math.max(50, Math.min((bounds.maxY - bounds.minY) / denom + CONTENT_PADDING * 2, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT));
123→  return {
124→    x: SHEET_MARGIN + 8,
125→    y: SHEET_MARGIN + 8,
126→    width,
127→    height,
128→  };
129→}
